sql:
SELECT name, nationality
FROM athletes
WHERE category_name = 'Marathon';

SELECT name 
FROM athletes 
WHERE bib_number IN (
  SELECT bib_number 
  FROM performances 
  WHERE performance_id = 1 AND gun_time = (
    SELECT MIN(performance_id) 
    FROM performances
  )
);

SELECT a.name AS athlete_name, c.name AS coach_name, a.team_name
FROM athletes a
JOIN coaches c ON a.coach_id = c.coach_id;

SELECT DISTINCT height
FROM athletes
WHERE team_name = 'Team A' AND coach_id IS NOT NULL;
